-- 6. Dartford Borough × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'dartford-borough',
  'Social media in Dartford Borough operates against a backdrop of national brand saturation that most small Kent towns do not face. Bluewater''s retailers maintain sophisticated social media presences that borough residents see daily. London brands fill the Instagram and Facebook feeds of the commuter population. New development marketing for The Bridge and Ebbsfleet sets a contemporary social standard. In this environment, a Dartford Borough business with a dormant Facebook page and no Instagram presence is not just missing an opportunity; it is actively signalling that it is not a serious operation. Yet most local businesses have exactly this problem. We build and optimise social media profiles that hold their own in Dartford Borough''s brand-saturated environment, configured for the specific platforms and audience behaviours that generate business in this high-intensity market.',
  'Dartford Borough''s social media landscape is influenced by its proximity to London and the presence of Bluewater. Residents follow and interact with national brands, London restaurants, and metropolitan lifestyle accounts, setting an unconscious benchmark for what business social media should look like. Local Facebook community groups for Dartford, Stone, Swanscombe, and the new developments are active with trade recommendation requests. Instagram is important for hospitality businesses competing against Bluewater''s dining options. LinkedIn is significant for the logistics, professional services, and B2B sector given the borough''s commercial density. TikTok reaches the younger demographic moving into the new developments.',
  'Social media quality in Dartford Borough splits between the national brands at Bluewater, which maintain polished presences, and independent businesses, which are largely absent or dormant. Community Facebook groups have strong engagement for trade recommendations, but many businesses tagged in recommendations have incomplete or dormant profiles. The hospitality sector near Bluewater is beginning to invest in Instagram but with inconsistent quality. The logistics and commercial sector has low LinkedIn engagement despite the audience being there.',
  'We set up social media for Dartford Borough businesses based on the platform and content style that drives results in this specific market. Trades get Facebook pages optimised for community group recommendation threads. Hospitality businesses get Instagram profiles configured to compete with Bluewater dining alternatives. B2B and logistics get LinkedIn company pages built for commercial credibility. Every profile is branded to the standard that borough residents, conditioned by national brand exposure, expect from any business they consider.',
  '{"population": 113000, "growth": "National brand presence raising social media expectations borough-wide", "business_districts": ["Dartford Town Centre", "Bluewater area", "Ebbsfleet", "The Bridge", "Stone", "Swanscombe"], "key_fact": "Bluewater and London commuter culture set social media standards higher than typical Kent markets"}',
  '[{"title": "Dartford businesses invisible in community group recommendation threads", "description": "When a resident of The Bridge or Stone posts in a Facebook group asking for a plumber, electrician, or restaurant recommendation, businesses without properly set up pages cannot be tagged or found. These community groups generate high-intent referrals daily. A business without a complete, professional Facebook presence is locked out of the borough''s most powerful word-of-mouth channel."}, {"title": "Hospitality social media losing to Bluewater dining alternatives", "description": "Dartford Borough restaurants and cafes compete with Bluewater''s branded dining options, which maintain professional social media across every platform. A local restaurant with a dormant Instagram and inconsistent Facebook presence loses the digital comparison before a potential customer even considers the food. In this market, social media presence is a competitive requirement, not an optional extra."}, {"title": "Commercial businesses with no LinkedIn presence in a B2B-heavy borough", "description": "Dartford''s logistics, professional services, and commercial sector generates significant LinkedIn activity, but most local businesses have no company page or one with minimal content. Commercial clients researching potential partners check LinkedIn. An absent or empty company page raises questions about the business''s professionalism and scale."}]',
  '[{"title": "Community-group-optimised Facebook for Dartford Borough trades", "description": "We build Facebook business pages optimised for engagement in Dartford''s active community groups. Professional branding that matches borough standards, complete service information, portfolio galleries, and review collection systems. When a resident recommends your business or searches for your page after seeing your van, they find a profile that converts their interest into a booking."}, {"title": "Bluewater-competitive Instagram for borough hospitality", "description": "We set up Instagram profiles for Dartford Borough restaurants, cafes, and entertainment businesses that compete visually with Bluewater''s branded dining. Professional photography guidelines, cohesive grid planning, story highlight organisation, and booking link integration. Every element is designed to match the social media standard borough residents encounter daily."}, {"title": "B2B LinkedIn presence for Dartford''s commercial sector", "description": "We build LinkedIn company pages for logistics, professional services, and commercial businesses that project the credibility B2B clients expect. Fleet showcases, capability descriptions, accreditation displays, and industry content positioning. Your LinkedIn presence supports the commercial relationships that drive revenue in Dartford''s B2B-heavy economy."}]',
  '[{"question": "Which social platform matters most for Dartford Borough businesses?", "answer": "For trades serving residential customers, Facebook is essential due to active community groups. For hospitality competing with Bluewater dining, Instagram is critical. For logistics and B2B, LinkedIn drives commercial relationships. For businesses targeting the young professional demographic at The Bridge and Ebbsfleet, Instagram and TikTok reach this audience. We recommend the platforms that match your specific customer base."}, {"question": "How important are the community Facebook groups in Dartford?", "answer": "Extremely important. Groups for Dartford, Stone, Swanscombe, and the new developments have thousands of active members posting recommendation requests regularly. Being properly represented in these groups generates consistent, high-quality leads with built-in social proof from the recommending neighbour."}, {"question": "Can social media really compete with Bluewater''s branded dining?", "answer": "Yes. Independent restaurants with strong, consistent Instagram presence successfully draw customers who might otherwise default to Bluewater''s chain options. The key is matching the professional visual standard while offering the authentic, independent experience that increasingly appeals to customers seeking alternatives to branded chains."}, {"question": "Do you manage social media ongoing or just set it up?", "answer": "This service focuses on professional setup: creating, branding, and optimising your profiles. We provide content templates, photography guidelines, and posting strategy documents so you can maintain your presence independently. Ongoing management is available as a separate service if you want hands-off social media."}]',
  'trust'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  local_context = EXCLUDED.local_context,
  competition_landscape = EXCLUDED.competition_landscape,
